class InvalidPasswordException extends Exception {
    public InvalidPasswordException(String msg) { super(msg); }
}

public class AuthSystem {
    static void validatePassword(String pwd) throws InvalidPasswordException {
        if(pwd.length() < 8) throw new InvalidPasswordException("Too short.");
        if(!pwd.matches(".*\\d.*")) throw new InvalidPasswordException("Must contain a digit.");
        if(!pwd.matches(".*[A-Z].*")) throw new InvalidPasswordException("Must contain uppercase.");
        System.out.println("Login Successful");
    }
}
